ALTER TABLE public.solicitacoes_troca_titularidade ADD COLUMN IF NOT EXISTS termo_cancelamento_url text; CREATE OR REPLACE FUNCTION public.placa_bloqueada_por_troca(p_placa text) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $func$ SELECT EXISTS ( SELECT 1 FROM public.solicitacoes_troca_titularidade s JOIN public.veiculos v ON v.id = s.veiculo_id WHERE upper(regexp_replace(coalesce(v.placa,''), '[^A-Za-z0-9]', '', 'g')) = upper(regexp_replace(coalesce(p_placa,''), '[^A-Za-z0-9]', '', 'g')) AND s.status IN ('cotacao_em_andamento','aguardando_cadastro','aguardando_monitoramento','aguardando_vistoria','liberada_para_assinatura') ); $func$; GRANT EXECUTE ON FUNCTION public.placa_bloqueada_por_troca(text) TO anon, authenticated, service_role; CREATE TABLE IF NOT EXISTS public.relacionamento_debitos_pendentes ( id uuid PRIMARY KEY DEFAULT gen_random_uuid(), solicitacao_troca_id uuid REFERENCES public.solicitacoes_troca_titularidade(id) ON DELETE CASCADE, associado_id uuid REFERENCES public.associados(id) ON DELETE SET NULL, cpf text NOT NULL, nome text, valor_total numeric(12,2) NOT NULL DEFAULT 0, quantidade_boletos int NOT NULL DEFAULT 0, detalhe_boletos jsonb, status text NOT NULL DEFAULT 'aberto', observacao text, responsavel_id uuid REFERENCES public.profiles(id) ON DELETE SET NULL, resolvido_em timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now() ); CREATE INDEX IF NOT EXISTS idx_relac_debitos_status ON public.relacionamento_debitos_pendentes(status, created_at DESC); CREATE INDEX IF NOT EXISTS idx_relac_debitos_cpf ON public.relacionamento_debitos_pendentes(cpf); ALTER TABLE public.relacionamento_debitos_pendentes ENABLE ROW LEVEL SECURITY; DROP POLICY IF EXISTS "Internos veem debitos relacionamento" ON public.relacionamento_debitos_pendentes; CREATE POLICY "Internos veem debitos relacionamento" ON public.relacionamento_debitos_pendentes FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM public.profiles p WHERE p.user_id = auth.uid() AND p.tipo = 'funcionario'::tipo_usuario)); DROP POLICY IF EXISTS "Internos atualizam debitos relacionamento" ON public.relacionamento_debitos_pendentes; CREATE POLICY "Internos atualizam debitos relacionamento" ON public.relacionamento_debitos_pendentes FOR UPDATE TO authenticated USING (EXISTS (SELECT 1 FROM public.profiles p WHERE p.user_id = auth.uid() AND p.tipo = 'funcionario'::tipo_usuario)); DROP POLICY IF EXISTS "Service role insere debitos relacionamento" ON public.relacionamento_debitos_pendentes; CREATE POLICY "Service role insere debitos relacionamento" ON public.relacionamento_debitos_pendentes FOR INSERT TO service_role WITH CHECK (true); DROP TRIGGER IF EXISTS trg_relac_debitos_updated_at ON public.relacionamento_debitos_pendentes; CREATE TRIGGER trg_relac_debitos_updated_at BEFORE UPDATE ON public.relacionamento_debitos_pendentes FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();